// src/components/ERPChatBot/ERPChatBot.jsx
import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import { 
  Send, X, Bot, Loader2, 
  Clock, MessageSquare, Trash2
} from 'lucide-react';
import './ERPChatBot.css';

const ERPChatBot = ({ studentId, studentName, onClose }) => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [showWelcome, setShowWelcome] = useState(true);
  const messagesEndRef = useRef(null);
  const inputRef = useRef(null);

  // Initial welcome message
  useEffect(() => {
    const welcomeMessage = {
      id: 1,
      text: `Hello ${studentName}! 👋 I'm your AI Assistant.\n\nI can help you with:\n• Courses & Teachers\n• Fees & Payments\n• Attendance & Timetable\n• Grades & GPA\n• Assignments & Tasks\n• Academic Progress\n• Batch Information\n\nAsk me anything about your university ERP.`,
      sender: 'bot',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      icon: '🤖'
    };

    setMessages([welcomeMessage]);
  }, [studentName]);

  // PURE AI: Send query to function-calling chatbot
  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = {
      id: Date.now(),
      text: input,
      sender: 'user',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      icon: '👤'
    };
    
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);
    setIsTyping(true);
    setShowWelcome(false);

    try {
      // Call pure AI chatbot endpoint
      const response = await axios.post('http://localhost:65000/api/chatbot/ask', {
        question: input
      }, {
        withCredentials: true,
        headers: {
          'Content-Type': 'application/json'
        }
      });

      setIsTyping(false);

      if (response.data.success) {
        const botMessage = {
          id: Date.now() + 1,
          text: response.data.answer,
          sender: 'bot',
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          icon: '🤖',
          isDataResponse: true
        };
        
        setMessages(prev => [...prev, botMessage]);
      } else {
        throw new Error(response.data.message || 'Failed to get response');
      }

    } catch (error) {
      setIsTyping(false);
      
      console.error("Chatbot error:", {
        status: error.response?.status,
        message: error.message
      });
      
      let errorMessage = "Sorry, I'm having trouble processing your question. Please try again.";
      
      if (error.response?.status === 401) {
        errorMessage = "Please log in to use the AI assistant.";
      } else if (error.response?.data?.message) {
        errorMessage = error.response.data.message;
      } else if (error.message.includes('Network Error')) {
        errorMessage = "Cannot connect to AI service. Please check your connection.";
      }
      
      const errorMsg = {
        id: Date.now() + 1,
        text: errorMessage,
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        icon: '🤖',
        isError: true
      };
      
      setMessages(prev => [...prev, errorMsg]);
      
    } finally {
      setIsLoading(false);
    }
  };

  // Clear chat history
  const handleClearChat = async () => {
    try {
      await axios.post('http://localhost:65000/api/chatbot/clear-history', {}, {
        withCredentials: true
      });
      
      const welcomeMessage = {
        id: 1,
        text: `Chat cleared! Hello again ${studentName}! 👋\n\nWhat would you like to know about your university ERP?`,
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        icon: '🤖'
      };
      
      setMessages([welcomeMessage]);
      setShowWelcome(true);
      
    } catch (error) {
      console.error("Error clearing chat:", error);
    }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  // Format message text with line breaks
  const formatMessage = (text) => {
    if (!text) return '';
    
    // Add line breaks for bullet points and numbered lists
    return text.split('\n').map((line, index) => {
      // Check if line starts with bullet or number
      const trimmedLine = line.trim();
      if (trimmedLine.startsWith('•') || trimmedLine.startsWith('-') || 
          /^\d+\./.test(trimmedLine) || /^[a-z]\)/.test(trimmedLine)) {
        return (
          <React.Fragment key={index}>
            <span className="list-indent">{line}</span>
            <br />
          </React.Fragment>
        );
      }
      
      return (
        <React.Fragment key={index}>
          {line}
          <br />
        </React.Fragment>
      );
    });
  };

  return (
    <div className="erp-chatbot">
      {/* Header */}
      <div className="chatbot-header">
        <div className="header-left">
          <div className="ai-badge">
            <Bot size={18} />
            <span>Pure AI Assistant</span>
          </div>
          <div className="student-info">
            <span className="student-name">{studentName}</span>
            <span className="student-id">• {studentId}</span>
          </div>
        </div>
        <div className="header-right">
          <button 
            className="clear-btn"
            onClick={handleClearChat}
            title="Clear chat history"
            aria-label="Clear chat"
          >
            <Trash2 size={16} />
          </button>
          <button 
            className="close-btn" 
            onClick={onClose} 
            aria-label="Close chat"
          >
            <X size={20} />
          </button>
        </div>
      </div>

      {/* Messages Container */}
      <div className="messages-container">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`message-bubble ${msg.sender} ${msg.isError ? 'error' : ''} ${msg.isDataResponse ? 'data-response' : ''}`}
          >
            <div className="message-icon">{msg.icon}</div>
            <div className="message-content">
              <div className="message-text">
                {formatMessage(msg.text)}
              </div>
              <div className="message-time">
                <Clock size={10} />
                {msg.timestamp}
              </div>
            </div>
          </div>
        ))}
        
        {isTyping && (
          <div className="message-bubble bot typing">
            <div className="message-icon">🤖</div>
            <div className="message-content">
              <div className="typing-indicator">
                <span></span>
                <span></span>
                <span></span>
              </div>
            </div>
          </div>
        )}
        
        <div ref={messagesEndRef} />
      </div>

      {/* Welcome Hint (only shown initially) */}
      {showWelcome && messages.length === 1 && (
        <div className="welcome-hint">
          <MessageSquare size={14} />
          <span>Type your question below. I'll fetch real-time data from your university records.</span>
        </div>
      )}

      {/* Input Area */}
      <div className="input-container">
        <div className="input-wrapper">
          <input
            ref={inputRef}
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyPress={handleKeyPress}
            placeholder="Ask about fees, attendance, grades, timetable, teachers, batch info..."
            className="chat-input"
            disabled={isLoading}
            aria-label="Type your question"
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isLoading}
            className="send-btn"
            aria-label="Send message"
          >
            {isLoading ? (
              <Loader2 size={18} className="spin" />
            ) : (
              <Send size={18} />
            )}
          </button>
        </div>
        <div className="input-hint">
          Press Enter to send • Ask natural questions like "How much fee do I owe?" or "What's my attendance?"
        </div>
      </div>
    </div>
  );
};

export default ERPChatBot;
